#include <bits/stdc++.h>
using namespace std;
priority_queue<int,vector<int>,greater<int>> q;
int n;
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		int o;
		cin>>o;
		if(o==1){
			int x;
			cin>>x;
			q.push(x);
		}else if(o==2){
			cout<<q.top()<<"\n";
		}else{
			q.pop();
		}
	}
	return 0;
}
